const express = require('express');
const multer = require('multer');
const fs = require('fs');
const xml2js = require('xml2js');

const app = express();
const upload = multer({ dest: 'uploads/' });

app.post('/upload-xml', upload.single('file'), (req, res) => {
    const filePath = req.file.path;

    fs.readFile(filePath, (err, data) => {
        if (err) {
            return res.status(500).send('Error reading file');
        }

        const parser = new xml2js.Parser({
            explicitArray: false,
            strict: true,
            // Disable external entities and DTDs
            xmlMode: true,
            validate: (parser) => {
                parser.on('error', (err) => {
                    throw new Error('Invalid XML');
                });
            }
        });

        parser.parseString(data, (err, result) => {
            if (err) {
                return res.status(400).send('Error parsing XML');
            }

            // Process the configuration settings
            const configSettings = result; // Extracted configuration settings
            res.json(configSettings);
        });
    });
});

app.listen(3000, () => {
    console.log('Server is running on port 3000');
});